# OpenClaw Build 1.0.4 self-extracting installer
import base64
import io
import subprocess
import sys
import textwrap
import zipfile
from pathlib import Path

APP_DIR = Path.home() / "Desktop" / "OpenClaw-Agent"
PAYLOAD = """"""

def main():
    APP_DIR.mkdir(parents=True, exist_ok=True)
    data = base64.b64decode(PAYLOAD.encode("ascii"))
    with zipfile.ZipFile(io.BytesIO(data), "r") as archive:
        archive.extractall(APP_DIR)
    launcher = Path.home() / "Desktop" / "START OpenClaw Build 1.0.4.bat"
    launcher.write_text(textwrap.dedent(f"""
        @echo off
        cd /d "{APP_DIR}"
        call START_OPENCLAW.bat
    """).strip() + "\n", encoding="utf-8")
    print(f"OpenClaw Build 1.0.4 installed to {APP_DIR}")
    print(f"Launcher created at {launcher}")
    if "--no-launch" not in sys.argv:
        subprocess.Popen(["cmd", "/c", str(launcher)], cwd=str(APP_DIR))

if __name__ == "__main__":
    main()
